CREATE TABLE fiscal.inventory_minimums(tenant_id uuid NOT NULL,product_id uuid NOT NULL REFERENCES fiscal.inventory_products(id),branch_id uuid NOT NULL,minimum_quantity numeric(18,6) NOT NULL CHECK(minimum_quantity>=0),updated_at timestamptz NOT NULL DEFAULT now(),PRIMARY KEY(tenant_id,product_id,branch_id));
CREATE TABLE fiscal.inventory_transfers(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id uuid NOT NULL,product_id uuid NOT NULL REFERENCES fiscal.inventory_products(id),from_branch_id uuid NOT NULL,to_branch_id uuid NOT NULL,quantity numeric(18,6) NOT NULL CHECK(quantity>0),actor_ref text NOT NULL,idempotency_key text NOT NULL,created_at timestamptz NOT NULL DEFAULT now(),UNIQUE(tenant_id,idempotency_key),CHECK(from_branch_id<>to_branch_id));
ALTER TABLE fiscal.inventory_minimums ENABLE ROW LEVEL SECURITY;ALTER TABLE fiscal.inventory_transfers ENABLE ROW LEVEL SECURITY;REVOKE ALL ON fiscal.inventory_minimums,fiscal.inventory_transfers FROM anon,authenticated;
